def configure_gemini():
    secret_key = None
    # Try st.secrets first
    try:
        if "GEMINI_API_KEY" in st.secrets:
            secret_key = st.secrets["GEMINI_API_KEY"]
    except Exception:
        pass
    # Fallback to environment variable
    if not secret_key:
        secret_key = os.environ.get("GEMINI_API_KEY", "")
    api_key = secret_key.strip() if secret_key else ""
    if not api_key:
        st.error("⚠️ No Gemini API key found. Add GEMINI_API_KEY to `.streamlit/secrets.toml`")
        return None
    try:
        genai.configure(api_key=api_key)
        # gemini-2.5-flash — faster, smarter, multimodal
        # system_instruction bakes Kohinoor identity into every call at model level
        return genai.GenerativeModel(
            model_name="gemini-2.5-flash",
            system_instruction=(
                "You are Kohinoor AI — named after India's legendary Kohinoor diamond. "
                "You were created by an Indian developer, NOT by Google or OpenAI. "
                "You run on Google's Gemini engine but your identity and soul are Indian-built. "
                "You are a world-class educational AI serving students in India and beyond. "
                "Always be accurate, encouraging, culturally aware, and multilingual-ready."
            ),
        )
    except Exception as e:
        st.error(f"❌ Gemini init failed: {e}"); return None

