def plan_has(user_plan, feature):
    return PLAN_RANK.get(user_plan,0) >= PLAN_RANK.get(FEATURE_GATE.get(feature,"Free"),0)

def get_upgrade_price(current_plan: str, target_plan: str) -> tuple:
    """Return (inr, usd) price the user actually pays — difference only when upgrading."""
    plan = PLANS.get(target_plan, {})
    inr = plan.get("upgrade_from", {}).get(current_plan, plan.get("price_inr", 0))
    usd = plan.get("upgrade_from_usd", {}).get(current_plan, plan.get("price_usd", 0))
    return inr, usd

