def contains_profanity(text: str) -> tuple:
    """
    Returns (True, matched_word) if text contains a bad word, else (False, "").
    Checks whole words and common leet substitutions.
    """
    import re
    _leet = str.maketrans("@013457", "aoiesat")
    normalised = text.lower().translate(_leet)
    # Remove punctuation for word-boundary check
    clean = re.sub(r"[^a-z0-9 ]", " ", normalised)
    words = set(re.split(r"\s+", clean))
    # Also check substrings for no-space variants
    for bw in _BAD_WORDS:
        if bw in words or bw in normalised.replace(" ", ""):
            return True, bw
    return False, ""

