import smtplib, random
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart

ADMIN_EMAIL = "admin.kohinoorai.in@gmail.com"

def _send_email(to_addr: str, subject: str, html_body: str) -> tuple:
    """Send an email. Returns (True, "") on success or (False, error_message) on failure."""
    try:
        app_pw = st.secrets.get("GMAIL_APP_PASSWORD", "").replace(" ", "")
        if not app_pw:
            return False, "GMAIL_APP_PASSWORD not found in secrets.toml"
        msg = MIMEMultipart("alternative")
        msg["Subject"] = subject
        msg["From"]    = f"Kohinoor AI <{ADMIN_EMAIL}>"
        msg["To"]      = to_addr
        msg.attach(MIMEText(html_body, "html"))
        with smtplib.SMTP_SSL("smtp.gmail.com", 465) as srv:
            srv.login(ADMIN_EMAIL, app_pw)
            srv.sendmail(ADMIN_EMAIL, to_addr, msg.as_string())
        return True, ""
    except Exception as e:
        return False, str(e)

