def daily_reset(u, username, db):
    """Reset question quota at midnight California time.
    Also manages streak: +1 if user asked yesterday, reset to 0 if they missed a day."""
    today = _today_pt()
    last  = u.get("last_reset", "")

    if last == today:
        return  # already reset today, nothing to do

    # ── Check plan expiry ─────────────────────────────────────
    expiry = u.get("plan_expiry")
    if expiry and u.get("plan", "Free") != "Free":
        from datetime import date
        try:
            if date.today() > date.fromisoformat(expiry):
                # Plan has expired — downgrade to Free
                u["plan"]         = "Free"
                u["plan_expiry"]  = None
                u["qs_limit"]     = PLANS["Free"]["qs_limit"]
                u["teacher_on"]   = False
                u["voice_on"]     = False
                u["ghost_on"]     = False
                u["badge"]        = badge_for(u.get("streak", 0))
                u["_plan_expired_notice"] = True  # flag to show message once
                if username != "_guest_":
                    save_db(db)
        except Exception:
            pass

    # Work out streak delta
    if last:
        try:
            from datetime import date
            last_d  = date.fromisoformat(last)
            today_d = date.fromisoformat(today)
            gap = (today_d - last_d).days
            if gap > 1:
                # Missed at least one full day — reset streak
                u["streak"] = 0
            # gap == 1 means consecutive day — streak is incremented
            # when the user actually asks a question (not at reset time)
        except Exception:
            pass

    # Reset daily question limit
    u["qs_limit"]   = PLANS.get(u["plan"], PLANS["Free"])["qs_limit"]
    u["last_reset"] = today
    # Recompute badge after potential streak reset
    u["badge"] = badge_for(u["streak"])
    if username != "_guest_":
        save_db(db)

def grant_plan(u_data, plan_name, db, username):
    """Instantly apply plan benefits the millisecond payment is confirmed.
    Updates u_data in place, persists to DB, and syncs session state."""
    plan = PLANS.get(plan_name, PLANS["Free"])

    # ── Apply plan fields immediately ─────────────────────────
    u_data["plan"]     = plan_name
    u_data["qs_limit"] = plan["qs_limit"]

    # ── Stamp 30-day expiry for paid plans ───────────────────
    if plan_name == "Free":
        u_data["plan_expiry"] = None
    else:
        from datetime import date, timedelta
        u_data["plan_expiry"] = (date.today() + timedelta(days=30)).isoformat()

    # ── Pro → instant Diamond badge ───────────────────────────
    if plan_name == "Pro":
        u_data["badge"]  = DIAMOND_BADGE
        u_data["streak"] = max(u_data.get("streak", 0), 50)
    else:
        u_data["badge"]  = badge_for(u_data.get("streak", 0))

    # ── Mode unlocks ──────────────────────────────────────────
    if plan_name in ("Student", "Pro"):
        pass   # teacher_on is toggled by user, just unlock it
    if plan_name == "Pro":
        pass   # voice/ghost unlocked by plan check, no flag needed

    # ── Persist to disk immediately ───────────────────────────
    if username and username != "_guest_":
        db[username] = u_data          # make sure db ref is current
        save_db(db)

    # ── Force session state refresh so UI updates same frame ──
    import streamlit as _st
    if "db" in _st.session_state:
        _st.session_state.db = db

