# CHAT SESSION STORAGE — Persistent named conversations
# ══════════════════════════════════════════════════════════════════
CHAT_STORE_FILE = "kohinoor_chats.json"

def load_chat_store() -> dict:
    """Load all saved chat sessions from disk."""
    if not os.path.exists(CHAT_STORE_FILE):
        return {}
    try:
        with open(CHAT_STORE_FILE) as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}

def save_chat_store(store: dict):
    """Persist chat sessions to disk."""
    try:
        with open(CHAT_STORE_FILE, "w") as f:
            json.dump(store, f, indent=2)
    except Exception:
        pass

def get_user_chats(username: str) -> dict:
    """Return all chats for a user. Each chat: {id: {name, messages, gemini_hist, ts}}"""
    store = load_chat_store()
    return store.get(username, {})

def save_user_chat(username: str, chat_id: str, chat_data: dict):
    """Save a single chat for a user."""
    store = load_chat_store()
    if username not in store:
        store[username] = {}
    store[username][chat_id] = chat_data
    save_chat_store(store)

def delete_user_chat(username: str, chat_id: str):
    """Delete a single chat."""
    store = load_chat_store()
    if username in store and chat_id in store[username]:
        del store[username][chat_id]
        save_chat_store(store)

def rename_user_chat(username: str, chat_id: str, new_name: str):
    """Rename a chat."""
    store = load_chat_store()
    if username in store and chat_id in store[username]:
        store[username][chat_id]["name"] = new_name[:60]
        save_chat_store(store)

def generate_chat_name(model, first_message: str) -> str:
    """Ask Gemini to generate a short chat title from the first message."""
    try:
        raw = model.generate_content(
            f"Generate a SHORT chat title (4-6 words max, no quotes, no punctuation) "
            f"for a conversation that starts with: '{first_message[:200]}'. "
            f"Return ONLY the title, nothing else."
        ).text.strip()
        # Clean up: remove quotes, limit length
        raw = raw.strip('"\'').strip()
        return raw[:60] if raw else first_message[:40]
    except Exception:
        return first_message[:40]

def new_chat_id() -> str:
    """Generate a unique chat ID."""
    return f"chat_{int(time.time() * 1000)}"

