# ── PAYMENT CARD HTML ─────────────────────────────────────────
def payment_card(plan_name, _user=None, _u_data=None, _db=None):
    UPI_ID   = "arjun.fernandes.ahs@okicici"
    UPI_NAME = "KohinoorAI"

    plan = PLANS[plan_name]
    _act_user   = _user or st.session_state.get("active_user")
    _act_u_data = _u_data or (st.session_state.db.get(_act_user, {}) if _act_user and "db" in st.session_state else None)
    _act_db     = _db or st.session_state.get("db", {})
    _current_plan = (_act_u_data or {}).get("plan", "Free")

    if PLAN_RANK.get(plan_name, 0) <= PLAN_RANK.get(_current_plan, 0):
        return

    pay_inr, _ = get_upgrade_price(_current_plan, plan_name)
    import urllib.parse as _ulp
    _gpay_url = (
        f"upi://pay?pa={UPI_ID}&pn={UPI_NAME}"
        f"&am={pay_inr}&cu=INR&tn=KohinoorAI+{plan_name}+plan"
    )
    _qr_enc = _ulp.quote_plus(_gpay_url)
    _qr_url = f"https://api.qrserver.com/v1/create-qr-code/?size=180x180&data={_qr_enc}&bgcolor=1A1005&color=F0C040&margin=14"

    st.markdown(f"### 💳 Get {plan['label']} — ₹{pay_inr}/month")
    st.markdown("Follow these 3 simple steps:")

    # ── STEP 1 ───────────────────────────────────────────────
    with st.expander("Step 1 — Pay via GPay", expanded=True):
        st.markdown(f"**Pay exactly ₹{pay_inr}** to UPI ID:")
        st.code(UPI_ID)
        st.markdown("📱 **On mobile:** tap the button below")
        st.markdown(
            f'<a href="{_gpay_url}" style="display:inline-block;background:#1a73e8;'
            f'color:#fff;font-weight:700;padding:10px 22px;border-radius:8px;'
            f'text-decoration:none;font-size:0.9rem;">Open GPay →</a>',
            unsafe_allow_html=True
        )
        st.markdown("🖥️ **On desktop:** scan this QR with your phone")
        st.markdown(
            f'<div style="margin:8px 0;">'
            f'<img src="{_qr_url}" width="160" style="border-radius:8px;" alt="GPay QR"/>'
            f'</div>',
            unsafe_allow_html=True
        )
        st.warning(f"⚠️ Pay exactly ₹{pay_inr} — do not change the amount or the activation will fail.")

    # ── STEP 2 ───────────────────────────────────────────────
    with st.expander("Step 2 — Copy your UPI Transaction ID", expanded=True):
        st.markdown("After paying, GPay shows a **Transaction ID** on the success screen.")
        st.markdown("It looks like: `T2412XXXXXXXXX` or `407622XXXXXX`")
        st.info("Copy that ID — you'll need it in Step 3.")

    # ── STEP 3 ───────────────────────────────────────────────
    if _act_user and _act_user != "_guest_" and _act_u_data is not None:
        with st.expander("Step 3 — Paste Transaction ID & Activate", expanded=True):
            _pid = st.text_input(
                f"Paste your UPI Transaction ID here",
                key=f"pid_{plan_name}",
                placeholder="e.g. T2412XXXXXXXXXXXXXXXXX"
            )
            if st.button(f"⚡ Activate {plan['label']} Now", key=f"activate_{plan_name}",
                         type="primary", use_container_width=True):
                if not _pid.strip():
                    st.warning("Please paste your UPI Transaction ID first.")
                elif len(_pid.strip()) < 10:
                    st.error("That doesn't look like a valid Transaction ID. Check and try again.")
                else:
                    _logs = _act_db.get("_payment_logs_", [])
                    if any(l.get("txn") == _pid.strip() for l in _logs):
                        st.error("⚠️ This Transaction ID has already been used.")
                    else:
                        _logs.append({
                            "user":         _act_user,
                            "plan":         plan_name,
                            "from_plan":    _current_plan,
                            "expected_inr": pay_inr,
                            "txn":          _pid.strip(),
                            "ts":           _today_pt(),
                            "method":       "GPay/UPI",
                            "verified":     False,
                        })
                        _act_db["_payment_logs_"] = _logs
                        _act_u_data["plan_source"] = "personal"
                        grant_plan(_act_u_data, plan_name, _act_db, _act_user)
                        _badge = " 💎 Diamond badge awarded!" if plan_name == "Pro" else ""
                        st.success(f"🎉 {plan['label']} activated!{_badge}")
                        st.balloons()
                        st.rerun()

