# OFFICE GROUP SCREEN
# ══════════════════════════════════════════════════════════════
OFFICE_GROUP_FILE = "kohinoor_office_groups.json"

def load_office_groups() -> dict:
    if not os.path.exists(OFFICE_GROUP_FILE):
        return {}
    try:
        with open(OFFICE_GROUP_FILE) as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}

def office_invite_valid(group_info: dict) -> bool:
    """Invite code is valid for 14 days from group creation."""
    created = group_info.get("created_at", 0)
    if not created:
        return True   # legacy groups without timestamp — allow
    return (time.time() - created) < (14 * 86400)

def save_office_groups(data: dict):
    try:
        with open(OFFICE_GROUP_FILE, "w") as f:
            json.dump(data, f, indent=2)
    except Exception:
        pass

def office_group_ping(group_id: str, username: str):
    """Record that a user just asked a question in the group (updates last_active)."""
    og = load_office_groups()
    if group_id in og and username in og[group_id].get("members", {}):
        og[group_id]["members"][username]["last_active"] = time.time()
        save_office_groups(og)

def office_member_status(member_data: dict, is_in_group_session: bool) -> tuple:
    """
    Returns (colour, reason) for the status light.
    Green  = in group, asked a question in last 10 min
    Amber  = in group, but no question in last 20 min
    Red    = on personal plan / not in group session
    """
    last_active = member_data.get("last_active", 0)
    elapsed     = time.time() - last_active          # seconds since last q
    if not is_in_group_session or last_active == 0:
        return "#e53935", "On personal plan / not in group"
    if elapsed <= 600:   # 10 min
        return "#43a047", "Active — asked a question in the last 10 min"
    if elapsed <= 1200:  # 20 min
        return "#fb8c00", "In group — no question in last 20 min"
    return "#e53935", "On personal plan / not in group"


