                _n_likes   = len(_p.get("likes", []))
                _tags_html = " ".join(
                    f'<span style="background:rgba(201,168,76,0.1);color:#C9A84C;'
                    f'font-size:0.65rem;padding:1px 7px;border-radius:10px;">#{t}</span>'
                    for t in _p.get("tags", [])[:3]
                )
                st.markdown(
                    f'<div style="background:rgba(255,255,255,0.025);'
                    f'border:1px solid rgba(201,168,76,0.15);border-radius:12px;'
                    f'padding:14px 16px;margin-bottom:8px;">'
                    f'<div style="color:#9A8A70;font-size:0.7rem;margin-bottom:5px;">'
                    f'📁 {_p.get("category","")} &nbsp;·&nbsp; @{_p.get("author","?")} '
                    f'&nbsp;·&nbsp; {_p_ts}</div>'
                    f'<div style="color:#F0C040;font-weight:700;font-size:0.92rem;margin-bottom:4px;">'
                    f'{_p.get("title","")}</div>'
                    f'<div style="color:#C8BCA8;font-size:0.8rem;margin-bottom:8px;">'
                    f'{_p.get("body","")[:160]}{"…" if len(_p.get("body",""))>160 else ""}</div>'
                    f'<div style="display:flex;align-items:center;gap:12px;">'
                    f'{_tags_html}'
                    f'<span style="color:#9A8A70;font-size:0.72rem;margin-left:auto;">'
                    f'💬 {_n_replies} &nbsp; ❤️ {_n_likes}</span>'
                    f'</div></div>',
                    unsafe_allow_html=True
                )
                if st.button(f"Open →", key=f"fopen_{_p['id']}"):
                    st.session_state["forum_state"]   = "view_post"
                    st.session_state["forum_post_id"] = _p["id"]
                    st.rerun()
